var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"오, 오오......!","JPN":"お、おお……！","ENG":"Oh... Ooh!","TWN":"噢，噢噢……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"좌표도, 침식파 농도도...... 교수님의 연구 자료에 나왔던 것과 완벽하게 일치해......!","JPN":"座標も、侵食波濃度も……教授の研究資料と完全一致している……！","ENG":"The coordinates and the Corruption Ray saturation... They all match the professor's research notes perfectly!","TWN":"無論是座標還是侵蝕波濃度……都跟教授研究的資料完美一致……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"틀림없습니다! 여기가 바로 그 유적으로 통하는 길이에요!","JPN":"間違いありません！　ここが遺跡に通じる道です！","ENG":"This must be it! We're on the path toward the ruins!","TWN":"沒錯了！這裡就是通往遺跡的道路！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 저희가 제대로 도착한 걸까요?","JPN":"リタお姉ちゃん、本当にここが目的地なんでしょうか？","ENG":"Do you think we're at the right spot, Rita?","TWN":"麗塔姐姐，我們到達目的地了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"맞겠지. 윌버 녀석이 목이 터져라 웃고 있잖아.","JPN":"合ってるんじゃないか。ウィルバーの奴があんなデカい声で笑ってるし。","ENG":"Probably. Wilbur's laughing his face off.","TWN":"應該是吧，看韋爾伯那傢伙笑得嗓子都啞了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"담배 피우느라 건성으로 대답하지 말고요.","JPN":"タバコを吸いながら適当に答えるのはやめてください。","ENG":"Come on, put out that smoke and answer me properly.","TWN":"別只顧抽煙，就隨便敷衍我。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이상하잖아요. 유적이라고 할 만한 건 아무리 주위를 살펴 봐도 없는걸요.","JPN":"おかしいと思いませんか。遺跡らしきものは周りに一つもないのに。","ENG":"Don't you think it's weird? There's nothing in the area that looks like ruins.","TWN":"不覺得奇怪嗎。這周圍不管怎麼看都沒有跟遺跡沾上邊的東西呀。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너도 어렴풋이 알고 있었잖아. 망상으로 끝날 거라는 걸.","JPN":"お前も薄々わかってんじゃないか。結局妄想で終わるってことを。","ENG":"You saw it coming too, didn't you? This trip is going to end up bursting his bubble.","TWN":"你也應該有所察覺了吧。一切只不過是他的幻想罷了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"들것이나 준비해 둬. 현실을 깨닫고 나면 졸도할 테니까.","JPN":"担架でも用意しておけ。あいつが現実を突きつけられて卒倒するかもしれないから。","ENG":"Get a stretcher ready. He's going to pass out the moment he realizes he's been duped.","TWN":"還是準備擔架吧。他認清到現實後就會暈過去的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇게 원하던 곳에 기어코 와 버렸군, 윌버.","JPN":"ついに夢見た場所に来てしまったな、ウィルバー。","ENG":"So you really made it after all, Wilbur.","TWN":"你終於來到了夢寐以求的地方，韋爾伯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그렇습니다. 정말 감격스러운 순간이에요.","JPN":"はい。本当に感激の瞬間です。","ENG":"Indeed. Words cannot describe how my heart swells at this moment.","TWN":"是啊，真是感慨萬千啊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이제 곧 유적으로 통하는 입구가 열리겠죠? 가슴이 두근거려 미치겠어요!","JPN":"もうすぐ遺跡に繋がる入口が開くでしょう。胸が高鳴り狂ってしまいそうです！","ENG":"The entrance to the ruins should open up soon. I feel like my heart is going to explode!","TWN":"通往遺跡的入口馬上就要打開了吧？我激動得快發瘋了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"두 눈 똑바로 뜨고 잘 봐. 유적은 없어.","JPN":"両目をしっかり開けて見ろ。遺跡はない。","ENG":"Look all you want. There are no ruins.","TWN":"睜開你的雙眼好好看看，這裡沒有遺跡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"피크닉은 끝이야. 프론트 베이로 떠나기 전에 마음의 준비나 해 둬.","JPN":"ピクニックはおしまいだ。フロントベイに行く心の準備でもしておけ。","ENG":"The picnic's over. You might as well as prepare yourself mentally before you head to Front Bay.","TWN":"郊遊結束了，做好去前灣的心理準備吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"후......","JPN":"ふ……","ENG":"Hah...","TWN":"呵……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"후훗...... 후후후후......!","JPN":"ふふふ……ふふふっ……！","ENG":"Hah hah... Bwa hah hah!","TWN":"嘻嘻……嘻嘻嘻嘻哈……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 웃지? 충격 때문에 정신이 나가기라도 했나?","JPN":"なぜ笑う？　衝撃のせいで頭がおかしくなってしまったのか？","ENG":"Why are you laughing? Have you lost your mind from the shock?","TWN":"笑什麼？難道是打擊太大所以精神錯亂了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};